import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Shield, UploadCloud } from 'lucide-react';

const Navbar = () => {
    const location = useLocation();

    return (
        <header>
            <div style={{ display: 'flex', alignItems: 'center' }}>
                <Shield size={28} color="#3b82f6" style={{ marginRight: '10px' }} />
                <h1>HybridGuard</h1>
            </div>
            <nav style={{ display: 'flex', gap: '20px' }}>
                <Link
                    to="/"
                    style={{
                        color: location.pathname === '/' ? '#60a5fa' : 'white',
                        textDecoration: 'none',
                        fontWeight: location.pathname === '/' ? 'bold' : 'normal'
                    }}
                >
                    Dashboard
                </Link>
                <Link
                    to="/upload"
                    style={{
                        color: location.pathname === '/upload' ? '#60a5fa' : 'white',
                        textDecoration: 'none',
                        fontWeight: location.pathname === '/upload' ? 'bold' : 'normal'
                    }}
                >
                    <span style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                        <UploadCloud size={18} />
                        Analyze Code
                    </span>
                </Link>
            </nav>
        </header>
    );
};

export default Navbar;
